solutions.cpp:
#include <iostream>
#include <vector>

class Solution {
	public:
		int peekQueue(const std::vector<int>& queue) {
			try {
				return queue[0];
			} catch (const std::out_of_range& e) {
				return -1;
			}
		}
	};

int main() {
	std::vector<int> queue = {1, 2, 3, 4, 5};
	Solution solution;
	std::cout << solution.peekQueue(queue) << std::endl;
	return 0;
}
